namespace CRMRSG.EntityFramework
{
    using System;
    using System.Data.Entity;
    using System.Data.Entity.Infrastructure;
    using System.Linq;
    using Microsoft.AspNet.SignalR;

    public partial class CRM_RSGEntities : DbContext
    {
        public CRM_RSGEntities()
            : base("name=CRM_RSGEntities")
        {
        }

        protected override void OnModelCreating(DbModelBuilder modelBuilder)
        {
            throw new UnintentionalCodeFirstException();
        }

        public virtual DbSet<bitacora> bitacoras { get; set; }
        public virtual DbSet<cita> citas { get; set; }
        public virtual DbSet<cliente> clientes { get; set; }
        public virtual DbSet<notificacione> notificaciones { get; set; }
        public virtual DbSet<oportunidade> oportunidades { get; set; }
        public virtual DbSet<reporte> reportes { get; set; }
        public virtual DbSet<role> roles { get; set; }
        public virtual DbSet<tarea> tareas { get; set; }
        public virtual DbSet<usuario> usuarios { get; set; }
        public virtual DbSet<contacto_cliente> contacto_cliente { get; set; }
        public virtual DbSet<nota_cliente> nota_cliente { get; set; }
        public virtual DbSet<tarea_cliente> tarea_cliente { get; set; }

        // ====================================================================
        // INTERCEPCIÓN AUTOMÁTICA CENTRALIZADA (CORRECCIÓN TOTAL DE SINTAXIS)
        // ====================================================================
        public override int SaveChanges()
        {
            int? currentUserId = null;
            string currentIp = "127.0.0.1";
            try
            {
                if (System.Web.HttpContext.Current != null)
                {
                    if (System.Web.HttpContext.Current.Session != null && System.Web.HttpContext.Current.Session["UsuarioId"] != null)
                    {
                        currentUserId = Convert.ToInt32(System.Web.HttpContext.Current.Session["UsuarioId"]);
                    }
                    currentIp = System.Web.HttpContext.Current.Request.UserHostAddress;
                }
            }
            catch { }

            // Capturar auditorías antes de guardar (para Modificados y Eliminados)
            var listaAuditoria = new System.Collections.Generic.List<bitacora>();
            var entidadesModificadas = ChangeTracker.Entries()
                .Where(x => x.State == EntityState.Modified || x.State == EntityState.Deleted)
                .ToList();

            foreach (var entry in entidadesModificadas)
            {
                var tipoEntidad = System.Data.Entity.Core.Objects.ObjectContext.GetObjectType(entry.Entity.GetType());
                string nombreTabla = tipoEntidad.Name;
                
                // Evitamos auditar la propia bitácora
                if (nombreTabla == "bitacora") continue;

                string accion = entry.State == EntityState.Modified ? "Modificación" : "Eliminación";
                int idRegistro = 0;
                string valorAnterior = "";
                string valorNuevo = "";

                // Obtener llave primaria (asumimos que empieza por id_)
                var propId = entry.Entity.GetType().GetProperties()
                    .FirstOrDefault(p => p.Name.ToLower() == "id_" + nombreTabla.ToLower() || p.Name.ToLower() == "id_registro" || p.Name.ToLower() == "id_usuario");
                if (propId != null)
                {
                    idRegistro = Convert.ToInt32(propId.GetValue(entry.Entity) ?? 0);
                }

                if (entry.State == EntityState.Modified)
                {
                    var cambiosAnteriores = new System.Collections.Generic.List<string>();
                    var cambiosNuevos = new System.Collections.Generic.List<string>();
                    foreach (var propName in entry.OriginalValues.PropertyNames)
                    {
                        var originalVal = entry.OriginalValues[propName];
                        var currentVal = entry.CurrentValues[propName];
                        if ((originalVal != null && !originalVal.Equals(currentVal)) || (originalVal == null && currentVal != null))
                        {
                            cambiosAnteriores.Add($"{propName}: {originalVal}");
                            cambiosNuevos.Add($"{propName}: {currentVal}");
                        }
                    }
                    valorAnterior = string.Join("; ", cambiosAnteriores);
                    valorNuevo = string.Join("; ", cambiosNuevos);
                }
                else if (entry.State == EntityState.Deleted)
                {
                    var valores = new System.Collections.Generic.List<string>();
                    foreach (var propName in entry.OriginalValues.PropertyNames)
                    {
                        valores.Add($"{propName}: {entry.OriginalValues[propName]}");
                    }
                    valorAnterior = string.Join("; ", valores);
                }

                listaAuditoria.Add(new bitacora
                {
                    accion = accion,
                    tabla_afectada = nombreTabla,
                    id_registro_afectado = idRegistro,
                    valor_anterior = valorAnterior,
                    valor_nuevo = valorNuevo,
                    fecha_hora = DateTime.Now,
                    direccion_ip = currentIp,
                    id_usuario = currentUserId
                });
            }

            // Capturamos los registros nuevos antes de guardar para saber qué módulos se agregaron
            var registrosNuevos = ChangeTracker.Entries()
                .Where(x => x.State == EntityState.Added)
                .ToList();

            // Guardamos los cambios principales (Citas, Clientes, Tareas)
            int resultadoOriginal = base.SaveChanges();

            // Para los agregados, ahora que ya tienen ID asignado tras base.SaveChanges()
            if (registrosNuevos.Any())
            {
                using (var dbAudit = new CRM_RSGEntities())
                {
                    foreach (var entry in registrosNuevos)
                    {
                        var tipoEntidad = System.Data.Entity.Core.Objects.ObjectContext.GetObjectType(entry.Entity.GetType());
                        string nombreTabla = tipoEntidad.Name;
                        if (nombreTabla == "bitacora") continue;

                        int idRegistro = 0;
                        var propId = entry.Entity.GetType().GetProperties()
                            .FirstOrDefault(p => p.Name.ToLower() == "id_" + nombreTabla.ToLower() || p.Name.ToLower() == "id_registro" || p.Name.ToLower() == "id_usuario");
                        if (propId != null)
                        {
                            idRegistro = Convert.ToInt32(propId.GetValue(entry.Entity) ?? 0);
                        }

                        var valores = new System.Collections.Generic.List<string>();
                        foreach (var propName in entry.CurrentValues.PropertyNames)
                        {
                            valores.Add($"{propName}: {entry.CurrentValues[propName]}");
                        }

                        dbAudit.bitacoras.Add(new bitacora
                        {
                            accion = "Creación",
                            tabla_afectada = nombreTabla,
                            id_registro_afectado = idRegistro,
                            valor_nuevo = string.Join("; ", valores),
                            fecha_hora = DateTime.Now,
                            direccion_ip = currentIp,
                            id_usuario = currentUserId
                        });
                    }
                    dbAudit.SaveChanges();
                }

                // Generar notificaciones en tiempo real
                using (var dbNoti = new CRM_RSGEntities())
                {
                    bool huboAlertas = false;

                    foreach (var entrada in registrosNuevos)
                    {
                        // 1. Módulo de Citas
                        if (entrada.Entity is cita c)
                        {
                            string descCita = $"Se te ha asignado una nueva cita: {c.descripcion ?? "Reunión de actividad comercial"} en '{c.lugar ?? "Oficina"}' fijada para el {c.fecha.ToString("dd/MM/yyyy")} a las {c.hora}.";

                            dbNoti.notificaciones.Add(new notificacione
                            {
                                id_usuario = c.id_usuario,
                                mensaje = descCita,
                                fecha = DateTime.Now,
                                leida = false
                            });
                            huboAlertas = true;
                        }

                        // 2. Módulo de Gestión de Clientes
                        if (entrada.Entity is cliente cl)
                        {
                            int idAsignado = cl.id_usuario ?? 1;
                            string descCliente = $"Nuevo cliente asignado: Se te ha asignado el cliente {cl.nombre} de la empresa {cl.empresa ?? "Particular"}.";

                            dbNoti.notificaciones.Add(new notificacione
                            {
                                id_usuario = idAsignado,
                                mensaje = descCliente,
                                fecha = DateTime.Now,
                                leida = false
                            });
                            huboAlertas = true;
                        }

                        // 3. Módulo de Tareas
                        if (entrada.Entity is tarea t)
                        {
                            int idAsignadoTarea = t.id_usuario ?? 1;
                            string descTarea = $"Nueva tarea asignada: Tienes una actividad pendiente registrada bajo la categoría comercial.";

                            dbNoti.notificaciones.Add(new notificacione
                            {
                                id_usuario = idAsignadoTarea,
                                mensaje = descTarea,
                                fecha = DateTime.Now,
                                leida = false
                            });
                            huboAlertas = true;
                        }
                    }

                    if (huboAlertas)
                    {
                        dbNoti.SaveChanges();

                        // Disparador en tiempo real de SignalR
                        try
                        {
                            var hubContext = GlobalHost.ConnectionManager.GetHubContext("NotificationHub");
                            if (hubContext != null)
                            {
                                hubContext.Clients.All.notificarCambioSistema();
                            }
                        }
                        catch { }
                    }
                }
            }

            // Insertar auditoría de Modificados/Eliminados recopilados
            if (listaAuditoria.Any())
            {
                using (var dbAudit = new CRM_RSGEntities())
                {
                    dbAudit.bitacoras.AddRange(listaAuditoria);
                    dbAudit.SaveChanges();
                }
            }

            return resultadoOriginal;
        }
    }
